import express from 'express';
import path from 'path';
import { fileURLToPath } from 'url';
import dotenv from 'dotenv';
import fs from 'fs';
import crypto from 'crypto';
import cors from 'cors';
import helmet from 'helmet';
import compression from 'compression';
import { rateLimit } from 'express-rate-limit';
import validator from 'validator';

dotenv.config();

const __dirnameVar = typeof __dirname !== 'undefined'
  ? __dirname
  : path.dirname(fileURLToPath(import.meta.url));

const ROOT_DIR = fs.existsSync(path.join(__dirnameVar, 'package.json'))
  ? __dirnameVar
  : path.dirname(__dirnameVar);

const DB_FILE = path.join(ROOT_DIR, 'waitlist_db.json');

interface WaitlistEntry {
  id: string;
  contactInfo: string;
  tier: string;
  os: string;
  cpu: string;
  createdAt: string;
}

// Initialize database file safely
function initDb() {
  try {
    if (!fs.existsSync(DB_FILE)) {
      fs.writeFileSync(DB_FILE, JSON.stringify([], null, 2), 'utf8');
      console.log(`[TrustNode Database] Created empty waitlist database at ${DB_FILE}`);
    } else {
      console.log(`[TrustNode Database] Loaded existing database from ${DB_FILE}`);
    }
  } catch (error) {
    console.error('[TrustNode Database] Failed to initialize local JSON database:', error);
  }
}

initDb();

// Helper functions to read/write waitlist entries
async function readWaitlist(): Promise<WaitlistEntry[]> {
  try {
    const data = await fs.promises.readFile(DB_FILE, 'utf8');
    return JSON.parse(data);
  } catch (err) {
    console.error('[TrustNode Database] Error reading database, returning empty array', err);
    return [];
  }
}

async function writeWaitlist(entries: WaitlistEntry[]): Promise<boolean> {
  try {
    await fs.promises.writeFile(DB_FILE, JSON.stringify(entries, null, 2), 'utf8');
    return true;
  } catch (err) {
    console.error('[TrustNode Database] Error writing database', err);
    return false;
  }
}

// Authorization middleware for administrative routes
function adminAuth(req: express.Request, res: express.Response, next: express.NextFunction) {
  try {
    const providedKey = req.headers['x-admin-key'];
    const secretKey = process.env.ADMIN_KEY;

    if (!secretKey) {
      console.error('[TrustNode Security] ADMIN_KEY is not defined in server environment variables.');
      return res.status(401).json({ error: 'Unauthorized: Admin authentication not configured on server' });
    }

    if (!providedKey || typeof providedKey !== 'string') {
      return res.status(401).json({ error: 'Unauthorized: Missing or invalid credentials' });
    }

    // SHA-256 hashing ensures buffer lengths match exactly for timingSafeEqual, avoiding timing leakage or length-based crashes
    const keyHash = crypto.createHash('sha256').update(secretKey).digest();
    const providedHash = crypto.createHash('sha256').update(providedKey).digest();

    if (crypto.timingSafeEqual(keyHash, providedHash)) {
      return next();
    }

    return res.status(401).json({ error: 'Unauthorized: Access denied' });
  } catch (error) {
    console.error('[TrustNode Security] Error in admin authorization middleware:', error);
    return res.status(401).json({ error: 'Unauthorized' });
  }
}

async function startServer() {
  const app = express();
  const PORT = process.env.PORT || 3000;

  // Trust first proxy for accurate client IP identification in rate-limiting
  app.set('trust proxy', 1);

  // 1. Helmet security headers (relaxed CSP for Vite asset / font / worker compatibility)
  app.use(helmet({
    contentSecurityPolicy: false,
  }));

  // 1b. Gzip/deflate compression for all responses (HTML, JS, CSS, JSON API replies).
  // This is the single highest-impact change for slow connections and weak devices:
  // it typically shrinks JS/CSS payloads by 60-80%, meaning less data to download
  // and parse before the page can render.
  app.use(compression());

  // 2. Strict CORS configuration
  const allowedOrigin = process.env.ALLOWED_ORIGIN || 'https://trustnode.app';
  app.use(cors({
    origin: (origin, callback) => {
      // Disallow '*' and only allow explicitly matching production domain or same-origin requests.
      // Additionally, allow AI Studio development/preview domains (*.run.app, localhost, 127.0.0.1) so preview continues working.
      if (!origin) {
        return callback(null, true);
      }
      
      const isAllowedProd = origin === allowedOrigin;
      const isDevOrPreview = process.env.NODE_ENV !== 'production' || 
                             origin.includes('.run.app') || 
                             origin.includes('localhost') || 
                             origin.includes('127.0.0.1') ||
                             origin.includes('.studio');

      if (isAllowedProd || isDevOrPreview) {
        callback(null, true);
      } else {
        callback(new Error('Not allowed by CORS'));
      }
    },
    methods: ['GET', 'POST', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'X-Admin-Key'],
  }));

  app.use(express.json());

  // 3. Rate limiting for waitlist signup
  const waitlistLimiter = rateLimit({
    windowMs: 10 * 60 * 1000, // 10 minutes
    max: 5, // limit each IP to 5 requests per 10 minutes
    message: { error: 'Too many registration requests from this IP. Please try again after 10 minutes.' },
    standardHeaders: true,
    legacyHeaders: false,
  });

  // GET: Fetch all waitlist signups (Admin Route)
  app.get('/api/waitlist', adminAuth, async (req, res, next) => {
    try {
      const db = await readWaitlist();
      res.json(db);
    } catch (error) {
      next(error);
    }
  });

  // GET: Waitlist statistics (distributions) (Admin Route)
  app.get('/api/waitlist/stats', adminAuth, async (req, res, next) => {
    try {
      const db = await readWaitlist();
      
      const stats = {
        total: db.length,
        tiers: { free: 0, standard: 0, vip: 0 },
        os: { Android: 0, iOS: 0 },
        cpus: {} as Record<string, number>,
        recentActivity: db.slice(-10).reverse()
      };

      db.forEach(entry => {
        const tierKey = (entry.tier || 'standard').toLowerCase() as 'free' | 'standard' | 'vip';
        if (stats.tiers[tierKey] !== undefined) {
          stats.tiers[tierKey]++;
        } else {
          stats.tiers.standard++;
        }

        const osKey = entry.os === 'iOS' || entry.os?.toLowerCase().includes('ios') ? 'iOS' : 'Android';
        stats.os[osKey]++;

        const cpuName = entry.cpu || 'Unknown';
        stats.cpus[cpuName] = (stats.cpus[cpuName] || 0) + 1;
      });

      res.json(stats);
    } catch (error) {
      next(error);
    }
  });

  // POST: Create a waitlist signup and store in local JSON file
  app.post('/api/waitlist', waitlistLimiter, async (req, res, next) => {
    try {
      const { contactInfo, email, role, tier, os, cpu } = req.body;
      
      const rawContact = contactInfo || email;
      
      // Strict server-side validation of contactInfo
      if (typeof rawContact !== 'string') {
        return res.status(400).json({ error: 'Contact handle must be a string value.' });
      }

      const trimmedContact = rawContact.trim();
      if (trimmedContact === '') {
        return res.status(400).json({ error: 'Contact handle cannot be empty or whitespace only.' });
      }

      if (trimmedContact.length > 255) {
        return res.status(400).json({ error: 'Contact handle is too long (maximum 255 characters).' });
      }

      // Escape HTML characters before saving to prevent injection vulnerabilities
      const escapedContact = validator.escape(trimmedContact);

      const selectedTier = tier || role || 'standard';
      const selectedOs = os || 'Android';
      const selectedCpu = cpu || 'Unknown';

      // Generate a secure, unique, and branded ticket ID
      const randNum = Math.floor(1000 + Math.random() * 9000);
      const generatedTicket = `TN-2026-${selectedTier.toUpperCase()}-${selectedOs[0].toUpperCase()}${selectedCpu[0].toUpperCase()}-${randNum}`;

      const db = await readWaitlist();
      
      // Prevent exact duplicate signups for the same contact handle
      const duplicate = db.find(e => e.contactInfo.toLowerCase() === escapedContact.toLowerCase());
      if (duplicate) {
        // Uniform response structure (only success + token, no alreadyExists or timestamp)
        return res.json({ 
          success: true, 
          token: duplicate.id
        });
      }

      const newEntry: WaitlistEntry = {
        id: generatedTicket,
        contactInfo: escapedContact,
        tier: selectedTier,
        os: selectedOs,
        cpu: selectedCpu,
        createdAt: new Date().toISOString()
      };

      db.push(newEntry);
      const saved = await writeWaitlist(db);

      if (!saved) {
        throw new Error('Database write operation failed');
      }

      console.log(`[TrustNode Server] New registration saved successfully: ${escapedContact} (${selectedTier}) -> Token ${generatedTicket}`);
      
      // Uniform response structure (only success + token, no alreadyExists or timestamp)
      res.json({ success: true, token: generatedTicket });
    } catch (error) {
      next(error);
    }
  });

  // DELETE: Delete a waitlist registration (Admin Route)
  app.delete('/api/waitlist/:id', adminAuth, async (req, res, next) => {
    try {
      const { id } = req.params;
      const db = await readWaitlist();
      const filtered = db.filter(e => e.id !== id);

      if (db.length === filtered.length) {
        return res.status(404).json({ error: 'Record not found' });
      }

      await writeWaitlist(filtered);
      res.json({ success: true, message: 'Record deleted successfully' });
    } catch (error) {
      next(error);
    }
  });

  // Conscious design decision: Keeping rubert_fraud_int8.onnx available in public directory
  // so the browser can download/load it for local ONNX Runtime Web client-side inference demo.
  // We apply robust Cache-Control header to avoid redundant high-bandwidth downloads.
  app.use((req, res, next) => {
    if (req.path.endsWith('.onnx')) {
      res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
    }
    next();
  });

  // Serve Vite build static assets in production
  if (process.env.NODE_ENV !== 'production') {
    const { createServer: createViteServer } = await import('vite');
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(ROOT_DIR, 'dist');
    app.use(express.static(distPath, {
      // Vite's build output files inside /assets are content-hashed
      // (e.g. index-a1b2c3.js), so it's always safe to cache them for a
      // full year: if the content changes, the filename changes with it.
      // index.html itself is NOT hashed, so it must stay revalidated on
      // every request or users could get stuck on a stale build.
      setHeaders: (res, filePath) => {
        if (filePath.includes(`${path.sep}assets${path.sep}`)) {
          res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
        } else {
          res.setHeader('Cache-Control', 'no-cache');
        }
      },
    }));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'), (err) => {
        if (err) {
          res.status(404).send('TrustNode client application not built yet. Run `npm run build`.');
        }
      });
    });
  }

  // Basic global error-handling middleware (prevents leaking internal stack traces)
  app.use((err: any, req: express.Request, res: express.Response, next: express.NextFunction) => {
    console.error('[TrustNode Server Error Handler]:', err);
    res.status(500).json({ error: 'An unexpected internal server error occurred' });
  });

  if (process.env.NODE_ENV !== 'test') {
    app.listen(Number(PORT), '0.0.0.0', () => {
      console.log(`[TrustNode Server] Running on http://0.0.0.0:${PORT}`);
    });
  }

  return app;
}

startServer();
